const ctx = $('Switch: Active Flow Routes').item.json;
const adminsResult = $input.first().json;
const admins = Array.isArray(adminsResult) ? adminsResult : (adminsResult.items || []);
const now = new Date();
const israelOffset = 3 * 60;
const israelTime = new Date(now.getTime() + israelOffset * 60000);
const datetimeStr = israelTime.toISOString().replace('T', ' ').slice(0, 16);
const driverName = ctx.whoami?.driver_name || ctx.whoami?.full_name || 'לא ידוע';
const notifications = admins.filter(a => a.telegram_chat_id).map(a => ({
  chat_id: a.telegram_chat_id,
  text: `🚨 דיווח תאונה חדש\n\nנהג: ${driverName}\nזמן: ${datetimeStr}`,
  parse_mode: 'HTML'
}));
return notifications.map(n => ({ json: { notification: n, token: process.env.TELEGRAM_BOT_TOKEN } }));

const ctx = $('Switch: Main Router').first().json;
const rows = $input.all().map(i=>i.json).filter(r=>r.driver_id);
let lines = ['👥 נוכחות היום\n━━━━━━━━━━━━━━━━'];
if (rows.length===0) lines.push('אין נתוני נוכחות להיום.');
else rows.forEach(r=>{
  const ci=r.clock_in||'--:--';
  const co=r.clock_out;
  lines.push(`${co?'✅':'⏳'} ${r.driver_name||'—'}: ${ci}${co?` - ${co}`:''}`);
});
return [{ json: { ...ctx, attendanceText: lines.join('\n') } }];

const ctx = $('Switch: Main Router').item.json;
const kpi = $input.first().json;
const activeDrivers = kpi.active_drivers ?? kpi.drivers_clocked_in ?? 'N/A';
const activeVehicles = kpi.active_vehicles ?? kpi.vehicles_in_use ?? 'N/A';
const text = `🚗 סיכום צי\n━━━━━━━━━━━━━━━━\n\nנהגים מחוברים: ${activeDrivers}\nרכבים פעילים: ${activeVehicles}`;
return [{ json: { ...ctx, summaryText: text } }];

const ctx = $('Switch: Active Flow Routes').item.json;
const driversResult = $input.first().json;
const drivers = Array.isArray(driversResult) ? driversResult : (driversResult.items || []);
const withChat = drivers.filter(d => d.telegram_chat_id);
const count = withChat.length;
const broadcastMsg = ctx.text;
return [{ json: { ...ctx, broadcastMsg, driverCount: count, drivers: withChat } }];

const ctx = $('Switch: Active Flow Routes').item.json;
const state = ctx.sessionState || {};
const broadcastMsg = state.message || '';
const drivers = state.drivers || [];
return drivers.filter(d => d.telegram_chat_id).map(d => ({ json: { chatId: ctx.chatId, recipientChatId: d.telegram_chat_id, broadcastMsg } }));

const ctx = $('Switch: Main Router').first().json;
const res = $input.first().json;
const arr = Array.isArray(res) ? res : (res.items || [res]);
const v = arr[0];
let text;
if (!v || !v.vehicle_id) text = '🚗 לא נמצא רכב משויך לחשבונך.';
else text = `🚗 הרכב שלך\n━━━━━━━━━━━━━━━━\n\nיצרן: ${v.vendor||'-'}\nדגם: ${v.model||'-'}\nלוחית: ${v.licensing_plate||'-'}\nסוג: ${v.vehicle_type||'-'}\nק"מ נוכחי: ${v.current_km??'-'}`;
return [{ json: { chatId: ctx.chatId, text } }];

const ctx = $('Switch: Main Router').first().json;
const rows = $input.all().map(i=>i.json).filter(r=>r.work_date);
let csv = 'תאריך,כניסה,יציאה,שעות\n';
for (const r of rows) {
  let hrs='';
  if (r.clock_in && r.clock_out) {
    const [ih,im]=r.clock_in.split(':').map(Number);
    const [oh,om]=r.clock_out.split(':').map(Number);
    hrs=(((oh*60+om)-(ih*60+im))/60).toFixed(2);
  }
  const d=String(r.work_date).slice(0,10).split('-').reverse().join('/');
  csv+=`${d},${r.clock_in||''},${r.clock_out||''},${hrs}\n`;
}
const fileName=`attendance_${new Date().toISOString().slice(0,7)}.csv`;
const buf=Buffer.from('\uFEFF'+csv,'utf8');
return [{ json: { chatId: ctx.chatId, empty: rows.length===0 }, binary: { data: { data: buf.toString('base64'), fileName, mimeType:'text/csv' } } }];

const ctx = $('Code: Active Flow Router').first().json;
const res = $input.first().json;
const arr = Array.isArray(res)?res:(res.items||[res]);
const v = arr[0];
return [{ json: { chatId: ctx.chatId, vehicleId: (v&&v.vehicle_id)||null, message: ctx.text||'' } }];

const ctx = $('Code: Active Flow Router').first().json;
const field = ctx.callbackData;
const labels = {ud_license_valid:'תוקף רישיון (DD/MM/YYYY)', ud_license_number:'מספר רישיון', ud_phone:'מספר טלפון'};
const newState = { flow:'update_details', step:'awaiting_value', field };
return [{ json: { chatId: ctx.chatId, prompt: 'הזן/י ' + (labels[field]||'ערך') + ':', newState } }];

const ctx = $('Code: Active Flow Router').first().json;
const state = ctx.sessionState || {};
const field = state.field || '';
const raw = (ctx.text || '').trim();
let valid = true, errorMsg = '', column = '', value = raw;
if (field === 'ud_license_valid') {
  column = 'license_valid_to';
  const m = raw.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!m) { valid=false; errorMsg='⚠️ פורמט תאריך שגוי. הזן/י DD/MM/YYYY.'; }
  else value = `${m[3]}-${m[2]}-${m[1]}`;
} else if (field === 'ud_license_number') {
  column = 'license_number';
  if (!raw) { valid=false; errorMsg='⚠️ מספר רישיון לא תקין.'; }
} else if (field === 'ud_phone') {
  column = 'phone_number';
  if (!/^0\d{8,9}$/.test(raw)) { valid=false; errorMsg='⚠️ מספר טלפון לא תקין. דוגמה: 0501234567'; }
} else { valid=false; errorMsg='⚠️ שדה לא ידוע.'; }
return [{ json: { ...ctx, valid, errorMsg, column, value, driverId: ctx.whoami.driver_id } }];

const ctx = $('Switch: Main Router').first().json;
const res = $input.first().json;
const drivers = Array.isArray(res)?res:(res.items||[]);
const rows = drivers.slice(0,50).map(d=>[{ text: d.full_name||d.driver_id, callback_data:'ud2_driver_'+d.driver_id }]);
const keyboard = { inline_keyboard: rows.length?rows:[[{text:'אין נהגים', callback_data:'noop'}]] };
const newState = { flow:'update_driver', step:'awaiting_driver' };
return [{ json: { chatId: ctx.chatId, keyboard, newState } }];

const ctx = $('Code: Active Flow Router').first().json;
const targetDriverId = ctx.callbackData.replace('ud2_driver_','');
const newState = { flow:'update_driver', step:'awaiting_field', targetDriverId };
return [{ json: { chatId: ctx.chatId, newState } }];

const ctx = $('Code: Active Flow Router').first().json;
const map = {ud2_field_license_valid:'ud_license_valid', ud2_field_license_number:'ud_license_number', ud2_field_phone:'ud_phone'};
const field = map[ctx.callbackData]||'';
const state = ctx.sessionState||{};
const labels = {ud_license_valid:'תוקף רישיון (DD/MM/YYYY)', ud_license_number:'מספר רישיון', ud_phone:'מספר טלפון'};
const newState = { flow:'update_driver', step:'awaiting_value', field, targetDriverId: state.targetDriverId };
return [{ json: { chatId: ctx.chatId, prompt: 'הזן/י ' + (labels[field]||'ערך') + ':', newState } }];

const ctx = $('Code: Active Flow Router').first().json;
const state = ctx.sessionState || {};
const field = state.field || '';
const raw = (ctx.text || '').trim();
let valid = true, errorMsg = '', column = '', value = raw;
if (field === 'ud_license_valid') {
  column = 'license_valid_to';
  const m = raw.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!m) { valid=false; errorMsg='⚠️ פורמט תאריך שגוי. הזן/י DD/MM/YYYY.'; }
  else value = `${m[3]}-${m[2]}-${m[1]}`;
} else if (field === 'ud_license_number') {
  column = 'license_number';
  if (!raw) { valid=false; errorMsg='⚠️ מספר רישיון לא תקין.'; }
} else if (field === 'ud_phone') {
  column = 'phone_number';
  if (!/^0\d{8,9}$/.test(raw)) { valid=false; errorMsg='⚠️ מספר טלפון לא תקין. דוגמה: 0501234567'; }
} else { valid=false; errorMsg='⚠️ שדה לא ידוע.'; }
return [{ json: { ...ctx, valid, errorMsg, column, value, driverId: (state.targetDriverId) } }];

const ctx = $('Switch: Main Router').first().json;
const all = $input.all().map(i=>i.json);
const rows = all.filter(r=>r.licensing_plate && r.current_km!=null && r.next_maintenance_km!=null && r.current_km>=r.next_maintenance_km)
  .sort((a,b)=>(b.current_km-b.next_maintenance_km)-(a.current_km-a.next_maintenance_km));
let text;
if (!rows.length) text='✅ אין תחזוקות באיחור.';
else { text='📋 תחזוקות באיחור\n━━━━━━━━━━━━━━━━\n';
  for (const r of rows) text+=`\n🚗 ${r.licensing_plate} (${r.vendor||''} ${r.model||''})\n   ק"מ: ${r.current_km} / יעד: ${r.next_maintenance_km}\n   סוג: ${r.next_maintenance_type||'-'}\n`;
}
return [{ json: { chatId: ctx.chatId, text } }];

const ctx = $('Switch: Main Router').first().json;
const res = $input.first().json;
const vehicles = Array.isArray(res)?res:(res.items||[]);
const rows = vehicles.slice(0,50).map(v=>[{ text: (v.licensing_plate||'')+' '+(v.model||''), callback_data:'ml_veh_'+v.vehicle_id }]);
