const newState = { flow:'maint_log', step:'awaiting_type', vehicleId: setv.vehicleId };
return [{ json: { chatId: setv.chatId, keyboard, newState } }];

const ctx = $('Code: Active Flow Router').first().json;
const state = ctx.sessionState||{};
const maintType = ctx.callbackData.replace('ml_type_','');
const newState = { flow:'maint_log', step:'awaiting_km', vehicleId: state.vehicleId, maintType };
return [{ json: { chatId: ctx.chatId, newState } }];

const ctx = $('Code: Active Flow Router').first().json;
const state = ctx.sessionState||{};
const raw = (ctx.text||'').trim();
const km = parseInt(raw,10);
const valid = /^\d+$/.test(raw) && km>=0;
const today = new Date().toISOString().slice(0,10);
return [{ json: { chatId: ctx.chatId, valid, km, vehicleId: state.vehicleId, maintType: state.maintType, serviceDate: today, errorMsg:'⚠️ ק"מ לא תקין. הזן/י מספר.' } }];

const ctx = $('Switch: Main Router').first().json;
const r = $input.first().json || {};
let text;
if (r.result==='blocked') text=`⛔ דיווח נוכחות אפשרי רק בין ${r.window_start} ל-${r.window_end}.`;
else if (r.result==='already_in') text=`כבר נרשמת כניסה היום בשעה ${r.time}.`;
else if (r.result==='ok') text=`✅ כניסה נרשמה בהצלחה בשעה ${r.time}.`;
else text='⚠️ אירעה שגיאה ברישום הכניסה.';
return [{ json: { chatId: ctx.chatId, text } }];

